import{_ as n,o,c as a,a8 as t}from"./chunks/framework.DvHWw5tv.js";const g=JSON.parse('{"title":"mengyue-components","description":"","frontmatter":{},"headers":[],"relativePath":"plugin/mengyueComponents.md","filePath":"plugin/mengyueComponents.md"}'),r={name:"plugin/mengyueComponents.md"};function s(i,e,l,p,m,c){return o(),a("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776104037000"},[...e[0]||(e[0]=[t('<h1 id="mengyue-components" tabindex="-1">mengyue-components <a class="header-anchor" href="#mengyue-components" aria-label="Permalink to “mengyue-components”">​</a></h1><p><code>mengyue-components</code> 是本组件库的 <strong>正式版本</strong>。它在继承早期过渡版全部组件能力的基础上，完成了 API 的统一化设计与质量打磨，是当前推荐的生产级组件解决方案。</p><h2 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to “核心特性”">​</a></h2><ul><li><strong>Vue 3 + TypeScript</strong>：充分利用 Composition API 与类型推导，提供完整的 TS 类型定义。</li><li><strong>无第三方依赖</strong>：所有组件均为自研实现，样式与逻辑高度可控，避免外部库的版本捆绑。</li><li><strong>100% 测试覆盖</strong>：单元测试用例超过 200 个，确保每个组件的功能边界与交互行为稳定可靠。</li><li><strong>轻量级打包</strong>：全量引入体积不足 1MB，且天然支持按需加载，对项目体积几乎无负担。</li></ul><h2 id="与早期版本的区别" tabindex="-1">与早期版本的区别 <a class="header-anchor" href="#与早期版本的区别" aria-label="Permalink to “与早期版本的区别”">​</a></h2><p>相比于过渡版本 <code>mengyue-plus</code>，<code>mengyue-components</code> 进行了以下关键改进：</p><ul><li><strong>统一的 Props API</strong>：重新梳理并规范了所有组件的属性命名与使用方式，降低学习与记忆成本。</li><li><strong>缺陷修复</strong>：集中处理了早期版本中积累的已知问题，代码健壮性进一步提升。</li><li><strong>长期维护保障</strong>：作为正式版本，将持续接收功能迭代、性能优化与社区反馈修复。</li></ul><blockquote><p>功能层面二者完全对等，<strong>正式版是对早期版本的彻底完善与规范化</strong>。</p></blockquote><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to “适用场景”">​</a></h2><p><code>mengyue-components</code> 适用于所有基于 Vue 3 + TypeScript 构建的中后台系统、工具型产品及轻量化 Web 应用。其轻量、纯净的设计理念尤其适合对代码体积或定制自由度有较高要求的项目。</p><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to “快速开始”">​</a></h2><p>安装与引入方式请查阅 <a href="./../components/FastStart.html">快速开始</a> 章节。<br> 若你之前使用过 <code>mengyue-plus</code>，可参考 <a href="./../question/migration.html">迁移指南</a> 完成操作。<a href="./../plus/FastStart.html">点击此处</a>查看文档。</p>',12)])])}const u=n(r,[["render",s]]);export{g as __pageData,u as default};
